#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 505;
const int INF = 0x3f3f3f3f;
struct line{int to,wei,Db;};
int n,k,St,Ed,l,r,Ans,dis[N];char c[N][N];
vector<line> g[N];queue<int> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Add_edge(int x,int y,int z){
    int idx=g[x].size(),idy=g[y].size();
    g[x].pb({y,z,idy}),g[y].pb({x,0,idx});return;
}
void Build(int num){
    for(int i=1;i<=Ed;i++)g[i].clear();
    for(int i=1;i<=n;i++){
        Add_edge(St,i,num);
        Add_edge(i,i+n,k);
        Add_edge(i+2*n,i+3*n,k);
        Add_edge(i+3*n,Ed,num);
    }for(int i=1;i<=n;i++)for(int j=1;j<=n;j++)
        if(c[i][j]=='Y')Add_edge(i,j+3*n,1);
        else Add_edge(i+n,j+2*n,1);return;
}
bool BFS_Canit(){
    for(int i=1;i<=Ed;i++)dis[i]=0;
    while(!q.empty())q.pop();
    dis[St]=1,q.push(St);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(auto [v,w,id]:g[u])if(w&&!dis[v])
            {dis[v]=dis[u]+1;if(v==Ed)return 1;q.push(v);}
    }return 0;
}
int DFS_Cntflow(int u,int flow){
    if(u==Ed)return flow;int now=flow;
    for(auto &[v,w,id]:g[u]){
        if(now<=0)break;
        if(w&&dis[v]==dis[u]+1){
            int tmp=DFS_Cntflow(v,min(now,w));
            if(!tmp)dis[v]=0;else w-=tmp,g[v][id].wei+=tmp,now-=tmp;
        }
    }return flow-now;
}
int Sol_Dinic(){
    int res=0,flow=0;
    while(BFS_Canit())
        while(flow=DFS_Cntflow(St,INF))res+=flow;
    return res;
}
bool check(int num){Build(num);return (Sol_Dinic()==num*n);}
int main(){
    n=read(),k=read();
    St=n*4+1,Ed=n*4+2;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)cin>>c[i][j];
    l=0,r=n+k,Ans=0;
    while(l<=r){
        int mid=(l+r)/2;
        if(check(mid))Ans=mid,l=mid+1;
        else r=mid-1;
    }cout<<Ans<<"\n";
    return 0;
}
